var e={tag:"i18n-editor-examples",template:'<div class="ast-examples-global"><details><summary>AST Format Examples</summary><div class="example-list"><div class="example"><strong>Simple text:</strong> <code>"Hello world"</code></div><div class="example"><strong>Text with variable:</strong> <code>"Hello \\{{username}}"</code></div><div class="example"><strong>Plural (string-only options):</strong> <code>{"var": "count", "format": "plural", "options": {"=0": "no items", "one": "1 item", "other": "\\{{count}} items"}}</code></div><div class="example"><strong>Select/Switch:</strong> <code>{"var": "gender", "format": "select", "options": {"male": "He likes this", "female": "She likes this", "other": "They like this"}}</code></div><div class="example"><strong>Formatted number:</strong> <code>"Price: \\{{price|currency:USD}}"</code></div><div class="example"><strong>Complex example:</strong> <code>["You have ", {"var": "count", "format": "plural", "options": {"=0": "no messages", "other": "\\{{count}} messages from \\{{sender}}"}}, " in your inbox"]</code></div></div></details></div>'};export{e as default};
